import { Component, OnInit, inject, signal, computed, Input } from '@angular/core';
import { FormBuilder, FormGroup, FormsModule, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { CartModel } from '../../Models/Cart';
import { CommonModule, CurrencyPipe } from '@angular/common';
import { ButtonModule } from 'primeng/button';
import { InputNumberModule } from 'primeng/inputnumber';
import { DialogModule } from 'primeng/dialog';


@Component({
  selector: 'app-payment-process',
  templateUrl: './payment-process-component.html',
  styleUrls: ['./payment-process-component.scss'],
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    CurrencyPipe, // ✅ הוספה כאן
    ButtonModule,
    InputNumberModule,
    DialogModule,
    // כל שאר המודולים שאתה צריך
  ]
})
export class PaymentProcessComponent implements OnInit {

  private fb = inject(FormBuilder);
  private router = inject(Router);
  @Input() cartData!: CartModel | null;

  // שלבים
  steps = [
    { label: 'פרטים' },
    { label: 'תשלום' },
    { label: 'אישור' }
  ];

  currentStep = signal(0); // 0=פרטים, 1=תשלום, 2=אישור

  // טופס פרטים
  detailsForm!: FormGroup;

  // טופס תשלום
  paymentForm!: FormGroup;

  // כאן נוכל לדמות פרטי הזמנה
  orderSummary = {
    itemName: 'לרכב יוקרתית',
    quantity: 1,
    unitPrice: 50,
  };

  subtotal = computed(() => {
    if (!this.cartData) return 0;
    return this.cartData.items.reduce((sum, item) => sum + item.ticketPrice * item.quantity, 0);
  });


  // חישוב סכומים
  // subtotal = computed(() => this.orderSummary.quantity * this.orderSummary.unitPrice);
  shipping = 19.9;
  discount = 20;
  total = computed(() => this.subtotal() + this.shipping - this.discount);

  processing = signal(false);
  paymentSuccess = signal(false);

  ngOnInit(): void {


    const nav = this.router.getCurrentNavigation();
    if (nav?.extras.state && nav.extras.state['cartData']) {
      this.cartData = nav.extras.state['cartData'];
    }

    this.detailsForm = this.fb.group({
      email: ['', [Validators.required, Validators.email]],
      fullName: ['', Validators.required],
      phone: ['', Validators.required],
      acceptPrivacy: [false, Validators.requiredTrue],
      // כתובת
      country: ['Israel', Validators.required],
      city: ['', Validators.required],
      address: ['', Validators.required],
      zip: ['', Validators.required],
    });

    this.paymentForm = this.fb.group({
      cardName: ['', Validators.required],
      cardNumber: ['', [Validators.required, Validators.pattern(/^\d{16}$/)]],  // 16 ספרות
      expiry: ['', [Validators.required, Validators.pattern(/^(0[1-9]|1[0-2])\/\d{2}$/)]],  // MM/YY
      cvv: ['', [Validators.required, Validators.pattern(/^\d{3}$/)]],
      saveCard: [false]
    });
  }

  nextStep() {
    if (this.currentStep() === 0 && this.detailsForm.invalid) {
      this.detailsForm.markAllAsTouched();
      return;
    }
    if (this.currentStep() === 1 && this.paymentForm.invalid) {
      this.paymentForm.markAllAsTouched();
      return;
    }
    this.currentStep.update(v => v + 1);
  }

  previousStep() {
    this.currentStep.update(v => Math.max(0, v - 1));
  }

  confirmPayment() {
    if (this.paymentForm.invalid) {
      this.paymentForm.markAllAsTouched();
      return;
    }
    this.processing.set(true);

    // סימולציה של תשלום - נניח 2 שניות לעיבוד
    setTimeout(() => {
      this.processing.set(false);
      this.paymentSuccess.set(true);
      this.currentStep.set(2);
    }, 2000);
  }

}
<div class="payment-container">

  <div class="steps-header">
    <div *ngFor="let step of steps; let i = index" class="step" [class.active]="i === currentStep()">
      <div class="step-number">{{ i + 1 }}</div>
      <div class="step-label">{{ step.label }}</div>
    </div>
  </div>

  <div class="steps-content">

    <!-- שלב 1: פרטים -->
    <form *ngIf="currentStep() === 0" [formGroup]="detailsForm" (ngSubmit)="nextStep()">
      <h3>פרטי תשלום</h3>

      <label>אימייל לקבלת קבלה</label>
      <input type="email" formControlName="email" placeholder="example@mail.com" />
      <div *ngIf="detailsForm.get('email')?.invalid && detailsForm.get('email')?.touched" class="error">
        נא להזין אימייל תקין
      </div>

      <label>שם מלא</label>
      <input type="text" formControlName="fullName" placeholder="שם בעל/ת הכרטיס" />
      <div *ngIf="detailsForm.get('fullName')?.invalid && detailsForm.get('fullName')?.touched" class="error">
        שדה חובה
      </div>

      <label>טלפון</label>
      <input type="tel" formControlName="phone" placeholder="050-1234567" />
      <div *ngIf="detailsForm.get('phone')?.invalid && detailsForm.get('phone')?.touched" class="error">
        שדה חובה
      </div>

      <label>כתובת</label>
      <div class="address-row">
        <input type="text" formControlName="country" placeholder="מדינה" />
        <input type="text" formControlName="city" placeholder="עיר" />
      </div>
      <input type="text" formControlName="address" placeholder="כתובת" />
      <input type="text" formControlName="zip" placeholder="מיקוד" />

      <div>
        <input type="checkbox" formControlName="acceptPrivacy" id="privacy" />
        <label for="privacy">אני מאשר/ת תנאי שימוש ומדיניות פרטיות</label>
      </div>

      <button type="submit" class="btn-next">המשך לתשלום</button>
    </form>

    <!-- שלב 2: תשלום -->
    <form *ngIf="currentStep() === 1" [formGroup]="paymentForm" (ngSubmit)="confirmPayment()">
      <h3>פרטי אשראי</h3>

      <label>שם בעל/ת הכרטיס</label>
      <input type="text" formControlName="cardName" placeholder="שם מלא על הכרטיס" />
      <div *ngIf="paymentForm.get('cardName')?.invalid && paymentForm.get('cardName')?.touched" class="error">
        שדה חובה
      </div>

      <label>מספר כרטיס</label>
      <input type="text" formControlName="cardNumber" maxlength="16" placeholder="1234 5678 9012 3456" />
      <div *ngIf="paymentForm.get('cardNumber')?.invalid && paymentForm.get('cardNumber')?.touched" class="error">
        נא להזין 16 ספרות
      </div>

      <label>תוקף (MM/YY)</label>
      <input type="text" formControlName="expiry" maxlength="5" placeholder="MM/YY" />
      <div *ngIf="paymentForm.get('expiry')?.invalid && paymentForm.get('expiry')?.touched" class="error">
        תוקף לא תקין
      </div>

      <label>CVV</label>
      <input type="text" formControlName="cvv" maxlength="3" placeholder="123" />
      <div *ngIf="paymentForm.get('cvv')?.invalid && paymentForm.get('cvv')?.touched" class="error">
        נא להזין 3 ספרות
      </div>

      <div>
        <input type="checkbox" formControlName="saveCard" id="saveCard" />
        <label for="saveCard">שמור כרטיס לתשלומים עתידיים</label>
      </div>

      <div class="actions">
        <button type="button" (click)="previousStep()" class="btn-back">חזרה לפרטים</button>
        <button type="submit" [disabled]="processing()" class="btn-pay">
          <span *ngIf="processing()">מעבד...</span>
          <span *ngIf="!processing()">שלם עכשיו 🔒</span>
        </button>
      </div>
    </form>

    <!-- שלב 3: אישור -->
    <div *ngIf="currentStep() === 2" class="confirmation">
      <h3>תודה על הרכישה!</h3>
      <p>ההזמנה שלך נקלטה בהצלחה.</p>

      <div class="order-summary">
        <div><strong>פריט:</strong> {{ orderSummary.itemName }}</div>
        <div><strong>כמות:</strong> {{ orderSummary.quantity }}</div>
        <div><strong>מחיר ליחידה:</strong> {{ orderSummary.unitPrice | currency:'ILS' }}</div>
        <div><strong>סה"כ:</strong> {{ subtotal() | currency:'ILS' }}</div>
        <div><strong>משלוח:</strong> {{ shipping | currency:'ILS' }}</div>
        <div><strong>הנחה:</strong> -{{ discount | currency:'ILS' }}</div>
        <hr />
        <div><strong>סכום לתשלום:</strong> {{ total() | currency:'ILS' }}</div>
      </div>

      <button (click)="router.navigate(['/'])" class="btn-home">חזרה לעמוד הראשי</button>
    </div>
  </div>

</div>
